import { useContext } from "react";
import { Link } from "react-router-dom";
import { UserContext } from "../context/UserContext";

const Header = () => {
  const { user } = useContext(UserContext);

  const logout =()=>{
    console.log("assc")
    document.cookie = "token" + '=; Max-Age=-99999999;';  
    window.location.reload();
}
  return (
    <header className="h-8"> 
    <div>
      <ul className="flex bg-red-600 justify-between items-center px-4 py-2 h-full"> {/* Make sure the ul matches the header height */}
        <li><Link to="/">HOME</Link></li>
        <li><Link to="/about">ABOUT</Link></li>
        <li><Link to="/contact">CONTACT</Link></li>
        <li>{user}</li>
        {user ? (
          <li> 
            <button onClick={logout} className="bg-white text-red-600 px-3 py-1 rounded-md hover:bg-red-100">Logout</button>
          </li>  
        ) : (
          <li> 
            <Link to="/register" className="bg-white text-red-600 px-3 py-1 rounded-md hover:bg-red-100">Register</Link>
          </li>
        )}
      </ul>
    </div>
  </header>
  );
};

export default Header;
